const checkpoints = [];
const posts = JSON.parse(localStorage.getItem('blog_posts') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_blog_posts') || '[]');

// Qualifying posts: tagged with 'fantasy' and text contains 'worldbuilding'
const qTerm = 'worldbuilding';
const qualifyingPosts = posts.filter(p => {
  if (!p || !Array.isArray(p.tags)) return false;
  if (!p.tags.includes('fantasy')) return false;
  const haystack = [p.title, p.excerpt, p.content].filter(Boolean).join(' ').toLowerCase();
  return haystack.includes(qTerm);
});

let newestQualifying = null;
if (qualifyingPosts.length > 0) {
  newestQualifying = qualifyingPosts.slice().sort((a, b) => {
    const da = new Date(a.publishedAt);
    const db = new Date(b.publishedAt);
    return db - da; // newest first
  })[0];
}

// Saved items that correspond to qualifying posts
const savedQualifying = saved.filter(s => {
  if (!s) return false;
  return qualifyingPosts.some(p => p.id === s.postId);
});

// CP1 (0.3): User saved at least one qualifying worldbuilding+fantasy post
checkpoints.push({
  passed: savedQualifying.length > 0,
  weight: 0.3
});

// CP2 (0.7): User saved the newest qualifying post
let savedNewest = false;
if (newestQualifying) {
  savedNewest = saved.some(s => s && s.postId === newestQualifying.id);
}
checkpoints.push({
  passed: savedNewest,
  weight: 0.7
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');
const targetEmail = 'alex@example.com';

const activeForEmail = subs.filter(s => s && s.isActive && s.email === targetEmail);

// CP1 (0.4): There is an active monthly subscription for this email
const hasMonthly = activeForEmail.some(s => s.updateFrequency === 'monthly');
checkpoints.push({
  passed: hasMonthly,
  weight: 0.4
});

// CP2 (0.6): Active subscription for this email is monthly, includes blog updates,
// and preferredGenres contains only 'fantasy' and 'science_fiction' (both included)
const qualifyingSub = activeForEmail.find(s => {
  if (!s || s.updateFrequency !== 'monthly') return false;
  if (s.includeBlogUpdates !== true) return false;
  if (!Array.isArray(s.preferredGenres)) return false;
  const genres = s.preferredGenres;
  const required = ['fantasy', 'science_fiction'];
  const includesRequired = required.every(g => genres.includes(g));
  if (!includesRequired) return false;
  const onlyRequired = genres.every(g => required.includes(g));
  if (!onlyRequired) return false;
  if (s.name !== 'Alex Reader') return false;
  return true;
});
checkpoints.push({
  passed: !!qualifyingSub,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const books = JSON.parse(localStorage.getItem('books') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');

// Qualifying books: Chronicles of Aria ebooks under $6
const qualifyingBooks = books.filter(b => {
  if (!b) return false;
  if (b.seriesCode !== 'chronicles_of_aria') return false;
  if (b.format !== 'ebook') return false;
  if (typeof b.price !== 'number') return false;
  return b.price < 6.0;
});

// Determine cheapest qualifying book
let cheapest = null;
if (qualifyingBooks.length > 0) {
  cheapest = qualifyingBooks.slice().sort((a, b) => {
    const pa = typeof a.price === 'number' ? a.price : Infinity;
    const pb = typeof b.price === 'number' ? b.price : Infinity;
    return pa - pb;
  })[0];
}

// Wishlist items that are qualifying books
const wishlistQualifying = wishlistItems.filter(wi => {
  if (!wi) return false;
  return qualifyingBooks.some(b => b.id === wi.bookId);
});

// CP1 (0.3): User added at least one qualifying Chronicles of Aria ebook under $6
checkpoints.push({
  passed: wishlistQualifying.length > 0,
  weight: 0.3
});

// CP2 (0.7): User added the cheapest qualifying ebook to the wishlist
let addedCheapest = false;
if (cheapest) {
  addedCheapest = wishlistItems.some(wi => wi && wi.bookId === cheapest.id);
}
checkpoints.push({
  passed: addedCheapest,
  weight: 0.7
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const books = JSON.parse(localStorage.getItem('books') || '[]');

// Skyward Saga books sorted by oldest publication date
const skywardBooks = books.filter(b => b && b.seriesCode === 'skyward_saga');
skywardBooks.sort((a, b) => {
  const da = new Date(a.publicationDate || 0);
  const db = new Date(b.publicationDate || 0);
  return da - db;
});
const firstThreeSkywardIds = skywardBooks.slice(0, 3).map(b => b.id);

// Reading lists named 'Spring Reading Plan'
const springLists = lists.filter(l => {
  if (!l || typeof l.name !== 'string') return false;
  return l.name.trim().toLowerCase() === 'spring reading plan';
});

// For each Spring list, count how many of the first 3 Skyward books it contains
let maxMatchCount = 0;
springLists.forEach(list => {
  const listItems = items.filter(i => i && i.readingListId === list.id);
  const count = listItems.reduce((acc, li) => {
    if (firstThreeSkywardIds.includes(li.bookId)) return acc + 1;
    return acc;
  }, 0);
  if (count > maxMatchCount) maxMatchCount = count;
});

// CP1 (0.3): A 'Spring Reading Plan' list exists that contains at least 1 of the first 3 Skyward Saga books
checkpoints.push({
  passed: springLists.length > 0 && maxMatchCount >= 1,
  weight: 0.3
});

// CP2 (0.3): ... contains at least 2 of the first 3 books
checkpoints.push({
  passed: springLists.length > 0 && maxMatchCount >= 2,
  weight: 0.3
});

// CP3 (0.4): ... contains all 3 of the first 3 books
checkpoints.push({
  passed: springLists.length > 0 && maxMatchCount >= 3,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const events = JSON.parse(localStorage.getItem('events') || '[]');
const sessions = JSON.parse(localStorage.getItem('event_sessions') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');
const myEvents = JSON.parse(localStorage.getItem('my_events') || '[]');

// Compute next calendar month range (UTC), mirroring BusinessLogic._getNextCalendarMonthRange
const now = new Date();
const year = now.getFullYear();
const month = now.getMonth(); // 0-based
const nextMonth = month === 11 ? 0 : month + 1;
const nextYear = month === 11 ? year + 1 : year;
const rangeStart = new Date(Date.UTC(nextYear, nextMonth, 1, 0, 0, 0, 0));
const rangeEnd = new Date(Date.UTC(nextYear, nextMonth + 1, 0, 23, 59, 59, 999));

function parseDate(val) {
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

// Online events with 'Live Q&A' in title, in next month, registration required
const liveEvents = events.filter(e => {
  if (!e) return false;
  if (e.eventType !== 'online') return false;
  if (!e.title || !/live q&a/i.test(e.title)) return false;
  const sd = parseDate(e.startDate);
  if (!sd) return false;
  if (sd < rangeStart || sd > rangeEnd) return false;
  if (e.registrationRequired !== true) return false;
  return true;
});

// Determine which sessions for these events are in the evening (>= 18:00 local time)
function sessionIsEveningForEvent(session, event) {
  const dt = parseDate(session.startDateTime);
  if (!dt) return false;
  let hour = null;
  if (event.timezone) {
    try {
      const parts = new Intl.DateTimeFormat('en-US', {
        hour: 'numeric',
        hour12: false,
        timeZone: event.timezone
      }).formatToParts(dt);
      const hourPart = parts.find(p => p.type === 'hour');
      hour = hourPart ? parseInt(hourPart.value, 10) : null;
    } catch (e) {
      hour = dt.getUTCHours();
    }
  } else {
    hour = dt.getUTCHours();
  }
  if (hour === null || isNaN(hour)) return false;
  return hour >= 18;
}

const qualifyingSessionIds = [];
sessions.forEach(s => {
  const event = liveEvents.find(e => e.id === s.eventId);
  if (!event) return;
  if (sessionIsEveningForEvent(s, event)) {
    qualifyingSessionIds.push(s.id);
  }
});

// Registrations by Jordan Lee for qualifying sessions
const qualifyingRegs = regs.filter(r => {
  if (!r) return false;
  if (r.attendeeName !== 'Jordan Lee') return false;
  if (r.attendeeEmail !== 'jordan@example.com') return false;
  if (r.status !== 'confirmed') return false;
  if (!qualifyingSessionIds.includes(r.sessionId)) return false;
  return true;
});

// CP1 (0.4): User registered (confirmed) for an eligible Live Q&A online event session next month in an evening time slot
checkpoints.push({
  passed: qualifyingRegs.length > 0,
  weight: 0.4
});

// Map sessionId -> eventId
const sessionToEventId = {};
sessions.forEach(s => {
  if (s && s.id && s.eventId) {
    sessionToEventId[s.id] = s.eventId;
  }
});

const qualifyingEventIdsFromRegs = qualifyingRegs
  .map(r => sessionToEventId[r.sessionId])
  .filter(id => !!id);

const savedQualifyingEvents = myEvents.filter(me => {
  if (!me || !me.eventId) return false;
  return qualifyingEventIdsFromRegs.includes(me.eventId);
});

// CP2 (0.6): The same eligible event was saved to My Events
checkpoints.push({
  passed: qualifyingRegs.length > 0 && savedQualifyingEvents.length > 0,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const chosenQuoteId = localStorage.getItem('task6_shareLinkQuoteId');
const quotes = JSON.parse(localStorage.getItem('quotes') || '[]');
const books = JSON.parse(localStorage.getItem('books') || '[]');

// Find the bookId for 'The Moonlit Archive'
let moonlitBookId = null;
for (let i = 0; i < books.length; i++) {
  const b = books[i];
  if (b && typeof b.title === 'string' && b.title === 'The Moonlit Archive') {
    moonlitBookId = b.id;
    break;
  }
}

// All quotes for The Moonlit Archive
const moonlitQuotes = quotes.filter(q => q && q.bookId === moonlitBookId);

// Determine the highest like count among these quotes
let topLikeCount = -1;
moonlitQuotes.forEach(q => {
  const likes = typeof q.likesCount === 'number' ? q.likesCount : 0;
  if (likes > topLikeCount) topLikeCount = likes;
});

const topQuotes = moonlitQuotes.filter(q => {
  const likes = typeof q.likesCount === 'number' ? q.likesCount : 0;
  return likes === topLikeCount && topLikeCount >= 0;
});
const topQuoteIds = topQuotes.map(q => q.id);

// Locate the quote the user copied
const chosenQuote = quotes.find(q => q && q.id === chosenQuoteId);

// CP1 (0.4): User copied a share link for a quote from 'The Moonlit Archive'
const copiedFromCorrectBook = !!chosenQuote && chosenQuote.bookId === moonlitBookId;
checkpoints.push({
  passed: copiedFromCorrectBook,
  weight: 0.4
});

// CP2 (0.6): The copied quote is the most-liked Moonlit Archive quote
const copiedTopQuote = copiedFromCorrectBook && topQuoteIds.includes(chosenQuoteId);
checkpoints.push({
  passed: copiedTopQuote,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const bundles = JSON.parse(localStorage.getItem('bundles') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cart = carts[0] || null;

// Qualifying bundles: active, format ebook/digital_only, price <= 25, totalBooks >= 4
const qualifyingBundleIds = bundles
  .filter(b => {
    if (!b) return false;
    if (!b.isActive) return false;
    if (b.format !== 'ebook' && b.format !== 'digital_only') return false;
    if (typeof b.price !== 'number') return false;
    if (b.price > 25.0) return false;
    if (typeof b.totalBooks !== 'number' || b.totalBooks < 4) return false;
    return true;
  })
  .map(b => b.id);

// Cart items in the current cart that are qualifying bundles
const qualifyingCartItems = cartItems.filter(ci => {
  if (!ci) return false;
  if (!cart || ci.cartId !== cart.id) return false;
  if (ci.itemType !== 'bundle') return false;
  if (!qualifyingBundleIds.includes(ci.itemId)) return false;
  if (typeof ci.quantity !== 'number' || ci.quantity <= 0) return false;
  return true;
});

// CP1 (1.0): At least one qualifying bundle was added to the cart
checkpoints.push({
  passed: qualifyingCartItems.length > 0,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const posts = JSON.parse(localStorage.getItem('blog_posts') || '[]');
const comments = JSON.parse(localStorage.getItem('blog_comments') || '[]');

function parseDate(val) {
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

// 2024 posts tagged 'writing_tips'
const posts2024 = posts.filter(p => {
  if (!p || !Array.isArray(p.tags)) return false;
  if (!p.tags.includes('writing_tips')) return false;
  const d = parseDate(p.publishedAt);
  if (!d) return false;
  return d.getFullYear() === 2024;
});

// Sort by most commented (commentCount desc, then publishedAt desc)
posts2024.sort((a, b) => {
  const ca = typeof a.commentCount === 'number' ? a.commentCount : 0;
  const cb = typeof b.commentCount === 'number' ? b.commentCount : 0;
  if (cb !== ca) return cb - ca;
  const da = parseDate(a.publishedAt) || new Date(0);
  const db = parseDate(b.publishedAt) || new Date(0);
  return db - da;
});

const topPost = posts2024[0] || null;

let hasCorrectComment = false;
if (topPost) {
  const expectedName = 'Taylor';
  const expectedEmail = 'taylor@example.com';
  const expectedText = 'These writing tips are very helpful. I plan to use at least two of them this week.';
  hasCorrectComment = comments.some(c => {
    if (!c) return false;
    if (c.postId !== topPost.id) return false;
    if (c.authorName !== expectedName) return false;
    if (c.authorEmail !== expectedEmail) return false;
    if (c.content !== expectedText) return false;
    return true;
  });
}

// CP1 (1.0): User submitted the specified comment on the correct top 2024 Writing Tips post
checkpoints.push({
  passed: !!hasCorrectComment,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
